package org.apache.commons.math3.util;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math3.util.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
}

package org.apache.commons.math3.util.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.distribution.BinomialDistribution;

import static org.junit.Assert.*;

public class StepDefs {
    private BinomialDistribution distribution;
    private double result;

    @Given("a BinomialDistribution with trials = {int} and p = {double}")
    public void a_BinomialDistribution_with_trials_and_p(int trials, double p) {
        try {
            distribution = new BinomialDistribution(trials, p);
        } catch (Exception e) {
            // Handle exception if needed
            System.out.println("Error creating distribution: " + e.getMessage());
        }
    }

    @When("I call inverseCumulativeProbability({double})")
    public void i_call_inverseCumulativeProbability(double probability) {
        try {
            result = distribution.inverseCumulativeProbability(probability);
        } catch (Exception e) {
            // Handle exception if needed
            System.out.println("Error calling inverseCumulativeProbability: " + e.getMessage());
            result = Double.NaN; // Set to NaN to indicate error
        }
    }

    @Then("the result should be {int}")
    public void the_result_should_be(int expectedResult) {
        assertEquals(expectedResult, result, 0.1); // Using delta for comparison
    }

    @Then("the calculation should not diverge to NaN")
    public void the_calculation_should_not_diverge_to_NaN() {
        assertFalse("Result should not be NaN", Double.isNaN(result));
    }
}

